-- ============================================================
-- Migración 017: Catálogo de Poblados CAEX
-- 
-- Crea la tabla caex_poblados con los 4,866 poblados de Guatemala
-- obtenidos del WS ObtenerListadoPoblados de CAEX Logistics.
--
-- Usada por PayloadBuilderService::buscarCodigoCaexPoblado()
-- para resolver automáticamente el CodigoPobladoDestino al
-- generar guías SOAP dinámicas via DynamicProvider.
--
-- Para re-importar datos frescos desde el WS:
--   php scratch/caex_import_poblados.php
-- ============================================================

CREATE TABLE IF NOT EXISTS `caex_poblados` (
  `codigo`             VARCHAR(20)  NOT NULL,
  `nombre`             VARCHAR(200) NOT NULL,
  `nombre_normalizado` VARCHAR(200) NOT NULL,
  `created_at`         DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at`         DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`codigo`),
  KEY `idx_nombre` (`nombre_normalizado`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;


-- Fin de migración 017
-- Fin de migracion 017
